import re
from datetime import datetime

def sort_strings(lst):
    def extract_numbers(s):
        return [int(t) for t in re.findall(r'\d+', s)]

    def extract_months(s):
        months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December']
        for month in months:
            if month in s:
                return months.index(month) + 1
        return None

    def extract_words(s):
        words = ['Zero', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten', 'Eleven', 'Twelve']
        for word in words:
            if word.lower() in s.lower():
                return words.index(word)
        return None

    def custom_sort_key(s):
        numbers = extract_numbers(s)
        if numbers:
            return (0, numbers)
        month = extract_months(s)
        if month:
            return (1, month)
        word = extract_words(s)
        if word:
            return (2, word)
        return (3, s)

    return sorted(lst, key=custom_sort_key)

def main():
    print(sort_strings(['iPhone 9', 'iPhone X', 'iPhone 11']))
    print(sort_strings(['31 January', '1 February', '15 March']))
    print(sort_strings(['Eight', 'Nine', 'Ten']))
    print(sort_strings(['10', '8', '9']))

if __name__ == "__main__":
    main()

import re
from datetime import datetime

def sort_strings(lst):
    def extract_numbers(s):
        return [int(t) for t in re.findall(r'\d+', s)]

    def extract_words(s):
        words = re.findall(r'[a-zA-Z]+', s)
        numbers = {}
        for word in words:
            if word.lower() in ['zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine', 'ten', 'eleven', 'twelve']:
                numbers[word] = ['zero', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine', 'ten', 'eleven', 'twelve'].index(word.lower())
            elif word.lower() in ['january', 'february', 'march', 'april', 'may', 'june', 'july', 'august', 'september', 'october', 'november', 'december']:
                numbers[word] = ['january', 'february', 'march', 'april', 'may', 'june', 'july', 'august', 'september', 'october', 'november', 'december'].index(word.lower())
        return numbers

    def extract_version(s):
        match = re.search(r'(\d+(?:\.\d+)*)', s)
        if match:
            return list(map(int, match.group(1).split('.')))
        else:
            return None

    def custom_sort_key(s):
        numbers = extract_numbers(s)
        words = extract_words(s)
        version = extract_version(s)
        if numbers:
            return (0, numbers)
        elif words:
            return (1, list(words.values()))
        elif version:
            return (2, version)
        else:
            return (3, s)

    return sorted(lst, key=custom_sort_key)

